// @ts-check

import { Command } from '../../utils/Command.js'
import { CommandType } from '../../utils/CommandType.js'

export class GetInstanceFieldHelper {
    /**
     * @param {Command | null | undefined} command
     * @param {string} fieldName
     * @returns {any}
     */
    static getFieldValue(command, fieldName) {
        if (!command || !command.payload || command.payload.length === 0) {
            return null
        }

        if (
            command.commandType === CommandType.SetInstanceField &&
            command.payload.length >= 3
        ) {
            const name = GetInstanceFieldHelper._getPayloadValue(command.payload[1])
            if (typeof name === 'string' && name === fieldName) {
                return GetInstanceFieldHelper._getPayloadValue(command.payload[2])
            }
        }

        if (command.commandType === CommandType.Array) {
            for (let i = 0; i < command.payload.length; i++) {
                const element = command.payload[i]
                if (element instanceof Command) {
                    const result = GetInstanceFieldHelper.getFieldValue(element, fieldName)
                    if (result !== null) {
                        return result
                    }
                }
            }
            return null
        }

        const firstPayload = command.payload[0]
        return firstPayload instanceof Command
            ? GetInstanceFieldHelper.getFieldValue(firstPayload, fieldName)
            : null
    }

    /**
     * @param {Command | null} command
     * @returns {string | null}
     * @throws {Error} if command is null or undefined
     */
    static getResultType(command) {
        if (!command) {
            throw new Error('GetInstanceFieldHelper.getResultType: command must not be null or undefined')
        }
        if (!command.payload || command.payload.length === 0) {
            return null
        }

        if (
            command.commandType === CommandType.GetResultType ||
            command.commandType === CommandType.GetType
        ) {
            return GetInstanceFieldHelper._getPayloadValue(command.payload[0])
        }

        if (command.commandType === CommandType.Array) {
            for (let i = 0; i < command.payload.length; i++) {
                const element = command.payload[i]
                if (element instanceof Command) {
                    const result = GetInstanceFieldHelper.getResultType(element)
                    if (result !== null) {
                        return result
                    }
                }
            }
            return null
        }

        const firstPayload = command.payload[0]
        return firstPayload instanceof Command
            ? GetInstanceFieldHelper.getResultType(firstPayload)
            : null
    }

    /**
     * @param {any} payloadItem
     * @returns {any}
     */
    static _getPayloadValue(payloadItem) {
        if (
            payloadItem instanceof Command &&
            payloadItem.commandType === CommandType.Value &&
            payloadItem.payload.length > 0
        ) {
            return payloadItem.payload[0]
        }
        return payloadItem
    }
}
